// Combine all data
MOCK_PLACES["all"] = [
  ...RESTAURANTS,
  ...PARKS,
  ...HISTORICAL,
  ...CAFES,
  ...ENTERTAINMENT,
  ...SHOPPING,
  ...HOTELS,
];

MOCK_PLACES["restaurant"] = RESTAURANTS;
MOCK_PLACES["park"] = PARKS;
MOCK_PLACES["historical"] = HISTORICAL;
MOCK_PLACES["cafe"] = CAFES;
MOCK_PLACES["entertainment"] = ENTERTAINMENT;
MOCK_PLACES["shopping"] = SHOPPING;
MOCK_PLACES["hotel"] = HOTELS;

export const fetchPlaces = async (
  category: CategoryId = "all",
): Promise<Place[]> => {
  // Simulate network delay for loading indicator demo
  await new Promise((resolve) => setTimeout(resolve, 1500));

  // Simulate random error (10% chance) to test error handling
  const shouldError = Math.random() < 0.1;
  if (shouldError) {
    throw new Error(
      "Network connection failed. Please check your internet and try again.",
    );
  }

  const places = MOCK_PLACES[category] || MOCK_PLACES["all"];

  // Sort by rating
  return places.sort((a, b) => b.rating - a.rating);
};

export const fetchPlaceById = async (id: string): Promise<Place | null> => {
  await new Promise((resolve) => setTimeout(resolve, 800));

  const allPlaces = MOCK_PLACES["all"];
  const place = allPlaces.find((p) => p.id === id);

  if (!place) {
    throw new Error("Place not found");
  }

  return place;
};
